from collections import defaultdict
from typing import Callable, Any

class EventEmitter:
    def __init__(self):
        self._listeners: dict[str, list[Callable]] = defaultdict(list)

    def on(self, event: str, listener: Callable):
        self._listeners[event].append(listener)

    def off(self, event: str, listener: Callable):
        self._listeners[event] = [l for l in self._listeners[event] if l != listener]

    def emit(self, event: str, data: Any = None):
        for listener in self._listeners.get(event, []):
            listener(data)

class StockExchange:
    def __init__(self):
        self._prices: dict[str, float] = {}
        self._observers: list[Callable] = []

    def add_observer(self, obs: Callable):
        self._observers.append(obs)

    def update_price(self, ticker: str, new_price: float):
        old_price = self._prices.get(ticker, 0.0)
        self._prices[ticker] = new_price
        for obs in self._observers:
            obs(ticker, old_price, new_price)

def price_alert(threshold: float = 5.0):
    def handler(ticker, old_p, new_p):
        if old_p > 0:
            change = abs(new_p - old_p) / old_p * 100
            if change > threshold:
                print(f"  ALERT: {ticker} moved {change:.1f}%  ${old_p:.2f}->${new_p:.2f}")
    return handler

def trading_bot(ticker, old_p, new_p):
    if old_p > 0 and new_p < old_p * 0.95:
        print(f"  BOT: BUY {ticker} at ${new_p:.2f} (dip)")
    elif old_p > 0 and new_p > old_p * 1.10:
        print(f"  BOT: SELL {ticker} at ${new_p:.2f} (gain)")

def audit_log(ticker, old_p, new_p):
    print(f"  LOG: {ticker} ${old_p:.2f} -> ${new_p:.2f}")

if __name__ == "__main__":
    print("=== Generic EventEmitter ===")
    bus = EventEmitter()
    bus.on("userCreated", lambda d: print(f"  Welcome email: {d}"))
    bus.on("userCreated", lambda d: print(f"  Audit log: {d}"))
    bus.emit("userCreated", "Alice")

    print("\n=== Stock Exchange ===")
    exchange = StockExchange()
    exchange.add_observer(price_alert(5.0))
    exchange.add_observer(trading_bot)
    exchange.add_observer(audit_log)

    exchange.update_price("AAPL", 150.00)
    exchange.update_price("AAPL", 142.00)
    exchange.update_price("GOOGL", 2800.00)
    exchange.update_price("GOOGL", 3100.00)
```

---

### When to Use
- Event-driven systems (user actions trigger multiple side effects)
- UI frameworks (React state changes re-render components)
- Message brokers (Kafka, RabbitMQ)
- Real-time features (chat, notifications, stock tickers)

### When NOT to Use
- Simple direct calls between two objects — Observer adds indirection
- When execution order matters (Observer doesn't guarantee order)
- Debugging: event chains harder to trace than direct calls

---

### Real-World Examples
| System | Observer Use |
|--------|-------------|
| React | `useState` / `useEffect` — state changes trigger re-renders |
| Node.js | `EventEmitter` — core of event-driven architecture |
| DOM | `addEventListener` / `removeEventListener` |
| Kafka | Producers publish, consumers subscribe to topics |
| Redux | `store.subscribe(listener)` |

---

### Interview Questions
1. **Observer vs Pub/Sub?** Observer: subject directly notifies observers. Pub/Sub: message broker mediates — publishers and subscribers don't know each other. Pub/Sub scales across processes.
2. **Memory leaks?** Always unsubscribe. React: cleanup in useEffect. Java: WeakReferences. Android: lifecycle-aware LiveData.
3. **Push vs Pull model?** Push: data sent with notification. Pull: just notify "changed", observer queries. Push is simpler; Pull more selective.
4. **React and Observer?** useState is the subject. Components are observers. setState triggers re-render of dependent components.
5. **Observer explosion?** Too many fine-grained events create spaghetti. Fix: coarser events, state management (Redux), event aggregation.

## Strategy Pattern — Swap Algorithms at Runtime

### What Problem Does It Solve?
When you have multiple algorithms for the same task and need to switch between them at runtime. Strategy eliminates long if/else or switch chains by encapsulating each algorithm in its own class behind a common interface.

---

### UML Class Diagram (Mermaid)

```mermaid
classDiagram
    class CompressionStrategy {
        <<interface>>
        +compress(data: byte[]) byte[]
    }
    class ZipCompression {
        +compress(data: byte[]) byte[]
    }
    class GzipCompression {
        +compress(data: byte[]) byte[]
    }
    class NoCompression {
        +compress(data: byte[]) byte[]
    }
    class FileProcessor {
        -strategy: CompressionStrategy
        +setStrategy(s: CompressionStrategy)
        +process(file: String) void
    }
    CompressionStrategy <|.. ZipCompression
    CompressionStrategy <|.. GzipCompression
    CompressionStrategy <|.. NoCompression
    FileProcessor --> CompressionStrategy
```

---

### Java Implementation (Compilable)

```java
import java.util.Arrays;
import java.util.List;

public class Main {

    // === Strategy Interface ===
    interface SortStrategy {
        int[] sort(int[] data);
        String getName();
    }

    static class BubbleSort implements SortStrategy {
        public int[] sort(int[] data) {
            int[] arr = data.clone();
            for (int i = 0; i < arr.length; i++)
                for (int j = 0; j < arr.length - 1 - i; j++)
                    if (arr[j] > arr[j + 1]) {
                        int tmp = arr[j]; arr[j] = arr[j + 1]; arr[j + 1] = tmp;
                    }
            return arr;
        }
        public String getName() { return "BubbleSort"; }
    }

    static class QuickSort implements SortStrategy {
        public int[] sort(int[] data) {
            int[] arr = data.clone();
            Arrays.sort(arr); // Uses dual-pivot quicksort
            return arr;
        }
        public String getName() { return "QuickSort"; }
    }

    static class InsertionSort implements SortStrategy {
        public int[] sort(int[] data) {
            int[] arr = data.clone();
            for (int i = 1; i < arr.length; i++) {
                int key = arr[i], j = i - 1;
                while (j >= 0 && arr[j] > key) { arr[j + 1] = arr[j]; j--; }
                arr[j + 1] = key;
            }
            return arr;
        }
        public String getName() { return "InsertionSort"; }
    }

    // === Context ===
    static class Sorter {
        private SortStrategy strategy;

        public Sorter(SortStrategy strategy) { this.strategy = strategy; }
        public void setStrategy(SortStrategy s) { this.strategy = s; }

        public int[] sort(int[] data) {
            System.out.println("  Using " + strategy.getName());
            return strategy.sort(data);
        }
    }

    // === Payment Strategy (real-world) ===
    interface PaymentStrategy {
        boolean pay(double amount);
    }

    static class CreditCard implements PaymentStrategy {
        private final String number;
        CreditCard(String num) { this.number = num; }
        public boolean pay(double amount) {
            System.out.printf("  Paid $%.2f via Credit Card ending %s%n",
                amount, number.substring(number.length() - 4));
            return true;
        }
    }

    static class PayPal implements PaymentStrategy {
        private final String email;
        PayPal(String email) { this.email = email; }
        public boolean pay(double amount) {
            System.out.printf("  Paid $%.2f via PayPal (%s)%n", amount, email);
            return true;
        }
    }

    static class Checkout {
        private PaymentStrategy strategy;
        public void setPaymentMethod(PaymentStrategy s) { this.strategy = s; }
        public boolean process(double amount) { return strategy.pay(amount); }
    }

    public static void main(String[] args) {
        int[] data = {38, 27, 43, 3, 9, 82, 10};

        System.out.println("=== Sort Strategy ===");
        Sorter sorter = new Sorter(new BubbleSort());
        System.out.println("  Result: " + Arrays.toString(sorter.sort(data)));

        sorter.setStrategy(new QuickSort());
        System.out.println("  Result: " + Arrays.toString(sorter.sort(data)));

        sorter.setStrategy(new InsertionSort());
        System.out.println("  Result: " + Arrays.toString(sorter.sort(data)));

        System.out.println("\n=== Payment Strategy ===");
        Checkout checkout = new Checkout();
        checkout.setPaymentMethod(new CreditCard("4111111111111234"));
        checkout.process(99.99);
        checkout.setPaymentMethod(new PayPal("user@example.com"));
        checkout.process(49.50);
    }
}
```

