import functools
import time
from abc import ABC, abstractmethod

# === OOP Decorator Pattern ===
class Logger(ABC):
    @abstractmethod
    def log(self, message: str): ...

class ConsoleLogger(Logger):
    def log(self, message: str):
        print(message)

class TimestampLogger(Logger):
    def __init__(self, inner: Logger):
        self.inner = inner
    def log(self, message: str):
        self.inner.log(f"[2026-03-28T10:30:00] {message}")

class UpperCaseLogger(Logger):
    def __init__(self, inner: Logger):
        self.inner = inner
    def log(self, message: str):
        self.inner.log(message.upper())

class PrefixLogger(Logger):
    def __init__(self, inner: Logger, prefix: str):
        self.inner = inner
        self.prefix = prefix
    def log(self, message: str):
        self.inner.log(f"{self.prefix} {message}")

# === Python @decorator (language feature) ===
def retry(max_attempts: int = 3, delay: float = 1.0):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts - 1:
                        raise
                    print(f"  Retry {attempt + 1}/{max_attempts} after error: {e}")
                    time.sleep(delay * (2 ** attempt))
        return wrapper
    return decorator

def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        elapsed = time.perf_counter() - start
        print(f"  {func.__name__} took {elapsed:.4f}s")
        return result
    return wrapper

@timer
@retry(max_attempts=2, delay=0.01)
def fetch_data(url: str) -> str:
    print(f"  Fetching {url}...")
    return f"Data from {url}"

if __name__ == "__main__":
    print("=== OOP Decorators ===")
    simple = ConsoleLogger()
    simple.log("Hello World")

    full = PrefixLogger(UpperCaseLogger(TimestampLogger(ConsoleLogger())), "[APP]")
    full.log("Fully decorated message")

    print("\n=== Python @decorator ===")
    result = fetch_data("https://api.example.com")
    print(f"  Result: {result}")
```

---

### When to Use
- Adding cross-cutting concerns: logging, caching, retry, auth, metrics
- When you need to combine behaviors flexibly (mix and match)
- Middleware chains (Express, Django, Spring interceptors)
- When inheritance would cause class explosion

### When NOT to Use
- Simple cases where a single subclass suffices
- When decorator ordering creates confusing behavior
- Performance-critical paths (each decorator adds a function call)

---

### Real-World Examples
| System | Decorator Use |
|--------|-------------|
| Java I/O | `BufferedReader(FileReader(file))` — wrap readers |
| Express.js | Middleware chain: auth -> logging -> handler |
| Python | `@functools.lru_cache`, `@retry`, `@login_required` |
| Spring | `@Transactional`, `@Cacheable` — AOP decorators |
| React | Higher-Order Components (`withAuth(Component)`) |

---

### Interview Questions
1. **Decorator vs inheritance?** Decorator adds behavior at runtime via composition. Inheritance is compile-time and creates tight coupling. Decorator avoids class explosion (N decorators vs 2^N subclasses).
2. **Decorator vs Proxy?** Same structure, different intent. Decorator enhances behavior. Proxy controls access. In practice, a caching proxy and caching decorator look identical.
3. **OOP Decorator vs Python @decorator?** OOP: wrapper class implementing same interface. Python @: function that wraps another function. Both add behavior transparently; different mechanisms.
4. **Order matters in Decorator chains?** Yes. `Timestamp(UpperCase(Console))` produces `[TIME] HELLO`. `UpperCase(Timestamp(Console))` produces `[TIME] HELLO` (timestamp also uppercased). Order determines behavior.
5. **How does Java I/O use Decorator?** `new BufferedReader(new InputStreamReader(new FileInputStream("file")))` — each wrapper adds behavior (buffering, character decoding) without modifying the inner stream.

## Adapter Pattern — Make Incompatible Interfaces Work Together

### What Problem Does It Solve?
You have existing code that expects one interface, but the actual implementation has a different interface. Adapter translates between them — like a power adapter for international plugs.

---

### UML Class Diagram (Mermaid)

```mermaid
classDiagram
    class PaymentProcessor {
        <<interface>>
        +charge(amount: double, currency: String) boolean
    }
    class LegacyPaymentGateway {
        +makePayment(cents: int, currencyCode: String) int
    }
    class PaymentAdapter {
        -legacy: LegacyPaymentGateway
        +charge(amount: double, currency: String) boolean
    }
    PaymentProcessor <|.. PaymentAdapter : implements
    PaymentAdapter --> LegacyPaymentGateway : wraps
```

---

### Java Implementation (Compilable)

```java
import java.util.HashMap;
import java.util.Map;

public class Main {

    // === Target interface (what our code expects) ===
    interface PaymentProcessor {
        boolean charge(double amount, String currency);
    }

    // === Legacy system (can't modify) ===
    static class LegacyGateway {
        public int makePayment(int cents, String currencyCode) {
            System.out.printf("  Legacy: charging %d cents (%s)%n", cents, currencyCode);
            return 1; // 1 = success
        }
    }

    // === Adapter ===
    static class LegacyAdapter implements PaymentProcessor {
        private final LegacyGateway legacy;
        LegacyAdapter(LegacyGateway legacy) { this.legacy = legacy; }

        public boolean charge(double amount, String currency) {
            int cents = (int) (amount * 100);
            return legacy.makePayment(cents, currency) == 1;
        }
    }

    // === API Response Adapter ===
    // External API returns different format
    static class ExternalUserResponse {
        String user_name;
        String email_address;
        int is_active;
        ExternalUserResponse(String name, String email, int active) {
            this.user_name = name; this.email_address = email; this.is_active = active;
        }
    }

    // Our app's model
    static class User {
        final String name;
        final String email;
        final boolean active;
        User(String name, String email, boolean active) {
            this.name = name; this.email = email; this.active = active;
        }
        public String toString() {
            return "User{name='" + name + "', email='" + email + "', active=" + active + "}";
        }
    }

    // Adapter function
    static User adaptUser(ExternalUserResponse ext) {
        return new User(ext.user_name, ext.email_address, ext.is_active == 1);
    }

    // === XML to JSON Adapter ===
    interface JsonDataSource {
        Map<String, String> getData();
    }

    static class XmlService {
        public String getXml() {
            return "<user><name>Alice</name><role>admin</role></user>";
        }
    }

    static class XmlToJsonAdapter implements JsonDataSource {
        private final XmlService xml;
        XmlToJsonAdapter(XmlService xml) { this.xml = xml; }

        public Map<String, String> getData() {
            // Simple XML parsing (production would use proper parser)
            String raw = xml.getXml();
            Map<String, String> result = new HashMap<>();
            result.put("name", extractTag(raw, "name"));
            result.put("role", extractTag(raw, "role"));
            return result;
        }

        private String extractTag(String xml, String tag) {
            int start = xml.indexOf("<" + tag + ">") + tag.length() + 2;
            int end = xml.indexOf("</" + tag + ">");
            return xml.substring(start, end);
        }
    }

    public static void main(String[] args) {
        System.out.println("=== Payment Adapter ===");
        PaymentProcessor processor = new LegacyAdapter(new LegacyGateway());
        boolean success = processor.charge(29.99, "USD");
        System.out.println("  Success: " + success);

        System.out.println("\n=== API Response Adapter ===");
        ExternalUserResponse ext = new ExternalUserResponse("alice_smith", "alice@example.com", 1);
        User user = adaptUser(ext);
        System.out.println("  " + user);

        System.out.println("\n=== XML to JSON Adapter ===");
        JsonDataSource source = new XmlToJsonAdapter(new XmlService());
        System.out.println("  " + source.getData());
    }
}
```

