class InventoryService:
    def check_stock(self, items: list[str]) -> bool:
        print(f"  Inventory: checking {items}")
        return True
    def reserve(self, items: list[str]):
        print(f"  Inventory: reserved {items}")
    def release(self, items: list[str]):
        print(f"  Inventory: released {items}")

class PaymentService:
    def charge(self, user_id: str, amount: float) -> bool:
        print(f"  Payment: charged ${amount:.2f} to {user_id}")
        return True

class ShippingService:
    def create_shipment(self, address: str, items: list[str]) -> str:
        import time
        tracking = f"TRK-{int(time.time())}"
        print(f"  Shipping: created {tracking}")
        return tracking

class NotificationService:
    def send_email(self, email: str, subject: str, body: str):
        print(f"  Notification: sent '{subject}' to {email}")

class OrderFacade:
    def __init__(self):
        self.inventory = InventoryService()
        self.payment = PaymentService()
        self.shipping = ShippingService()
        self.notification = NotificationService()

    def place_order(self, user_id: str, email: str,
                    address: str, items: list[str], total: float) -> str:
