import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {

    // === Entity ===
    static class User {
        final String id;
        String name;
        String email;
        boolean active;

        User(String id, String name, String email, boolean active) {
            this.id = id; this.name = name; this.email = email; this.active = active;
        }

        public String toString() {
            return "User{" + id + ", " + name + ", " + email + ", active=" + active + "}";
        }
    }

    // === Repository Interface ===
    interface UserRepository {
        Optional<User> findById(String id);
        Optional<User> findByEmail(String email);
        User save(User user);
        void delete(String id);
        List<User> findAll();
        List<User> findActive();
    }

    // === In-Memory Implementation (for testing) ===
    static class InMemoryUserRepo implements UserRepository {
        private final Map<String, User> store = new HashMap<>();

        public Optional<User> findById(String id) {
            return Optional.ofNullable(store.get(id));
        }

        public Optional<User> findByEmail(String email) {
            return store.values().stream()
                .filter(u -> u.email.equals(email)).findFirst();
        }

        public User save(User user) {
            store.put(user.id, user);
            System.out.println("    [InMemory] Saved: " + user);
            return user;
        }

        public void delete(String id) {
            store.remove(id);
            System.out.println("    [InMemory] Deleted: " + id);
        }

        public List<User> findAll() { return new ArrayList<>(store.values()); }

        public List<User> findActive() {
            return store.values().stream()
                .filter(u -> u.active).collect(Collectors.toList());
        }
    }

    // === "SQL" Implementation (simulated) ===
    static class SqlUserRepo implements UserRepository {
        private final Map<String, User> db = new HashMap<>();

        public Optional<User> findById(String id) {
            System.out.println("    [SQL] SELECT * FROM users WHERE id = '" + id + "'");
            return Optional.ofNullable(db.get(id));
        }

        public Optional<User> findByEmail(String email) {
            System.out.println("    [SQL] SELECT * FROM users WHERE email = '" + email + "'");
            return db.values().stream().filter(u -> u.email.equals(email)).findFirst();
        }

        public User save(User user) {
            System.out.println("    [SQL] INSERT INTO users VALUES ('" + user.id + "', '" + user.name + "')");
            db.put(user.id, user);
            return user;
        }

        public void delete(String id) {
            System.out.println("    [SQL] DELETE FROM users WHERE id = '" + id + "'");
            db.remove(id);
        }

        public List<User> findAll() {
            System.out.println("    [SQL] SELECT * FROM users");
            return new ArrayList<>(db.values());
        }

        public List<User> findActive() {
            System.out.println("    [SQL] SELECT * FROM users WHERE active = true");
            return db.values().stream().filter(u -> u.active).collect(Collectors.toList());
        }
    }

    // === Service (uses Repository — doesn't know which implementation) ===
    static class UserService {
