### Java Implementation (Compilable)

```java
import java.util.ArrayList;
import java.util.List;

public class Main {

    // ============ ANTI-PATTERN: God Object ============
    // BAD: One class does everything
    static class GodObject {
        public void createUser(String name) {
            System.out.println("  [GOD] Creating user: " + name);
        }
        public void sendEmail(String to, String subject) {
            System.out.println("  [GOD] Sending email to: " + to);
        }
        public void processPayment(double amount) {
            System.out.println("  [GOD] Processing $" + amount);
        }
        public void generateReport() {
            System.out.println("  [GOD] Generating report");
        }
        public void backupDatabase() {
            System.out.println("  [GOD] Backing up DB");
        }
    }

    // GOOD: Split into focused services
    static class UserService {
        public void createUser(String name) {
            System.out.println("  [GOOD] UserService creating: " + name);
        }
    }
    static class EmailService {
        public void send(String to, String subject) {
            System.out.println("  [GOOD] EmailService sending to: " + to);
        }
    }
    static class PaymentService {
        public void process(double amount) {
            System.out.println("  [GOOD] PaymentService: $" + amount);
        }
    }

    // ============ ANTI-PATTERN: Tight Coupling (DIP violation) ============
    // BAD: Direct instantiation
    static class BadOrderService {
        public void placeOrder() {
            // Hardcoded dependencies — untestable, unswappable
            System.out.println("  [BAD] new MySQLDB(), new SMTPMailer(), new StripePayment()");
        }
    }

    // GOOD: Depend on abstractions
    interface OrderRepo { void save(String order); }
    interface Mailer { void send(String to, String body); }

    static class GoodOrderService {
        private final OrderRepo repo;
        private final Mailer mailer;
        GoodOrderService(OrderRepo repo, Mailer mailer) {
            this.repo = repo; this.mailer = mailer;
        }
        public void placeOrder(String order, String email) {
            repo.save(order);
            mailer.send(email, "Order confirmed: " + order);
        }
    }

    // ============ CODE SMELL: Long Parameter List ============
    // BAD: 7 parameters
    static void createUserBad(String firstName, String lastName, String email,
                               String phone, String address, String city, String country) {
        System.out.println("  [BAD] Too many params: " + firstName + " " + lastName);
    }

    // GOOD: Use a parameter object
    static class CreateUserRequest {
        String firstName, lastName, email, phone, address, city, country;
        CreateUserRequest(String first, String last, String email) {
            this.firstName = first; this.lastName = last; this.email = email;
        }
    }

    static void createUserGood(CreateUserRequest req) {
        System.out.println("  [GOOD] Clean params: " + req.firstName + " " + req.lastName);
    }

    public static void main(String[] args) {
        System.out.println("=== Anti-Pattern: God Object ===");
        System.out.println("BAD (one class does everything):");
        GodObject god = new GodObject();
        god.createUser("Alice");
        god.sendEmail("alice@test.com", "Welcome");
        god.processPayment(99.99);

        System.out.println("\nGOOD (focused services):");
        new UserService().createUser("Alice");
        new EmailService().send("alice@test.com", "Welcome");
        new PaymentService().process(99.99);

        System.out.println("\n=== Anti-Pattern: Tight Coupling ===");
        System.out.println("BAD:");
        new BadOrderService().placeOrder();
        System.out.println("GOOD:");
        GoodOrderService good = new GoodOrderService(
            order -> System.out.println("  [GOOD] Repo saved: " + order),
            (to, body) -> System.out.println("  [GOOD] Mailer sent to " + to + ": " + body)
        );
        good.placeOrder("ORD-001", "alice@test.com");

        System.out.println("\n=== Code Smell: Long Parameter List ===");
        createUserBad("Alice", "Smith", "a@b.com", "555", "123 Main", "NYC", "US");
        createUserGood(new CreateUserRequest("Alice", "Smith", "a@b.com"));
    }
}
```

