# ============ CODE SMELLS TABLE ============
SMELLS = (
    "Code Smells: Long Method(>20 lines)->Extract methods | "
    "Long Param List(>3)->Parameter object | "
    "Duplicate Code->Extract function | "
    "Feature Envy->Move method | "
    "Shotgun Surgery->Better encapsulation | "
    "Primitive Obsession->Value objects | "
    "Data Clumps->Group into object | "
    "Refused Bequest->Use composition | "
    "Middle Man->Remove, call directly | "
    "Speculative Generality->Delete it (YAGNI)"
)

if __name__ == "__main__":
    print("=== Anti-Pattern: God Object ===")
    print("BAD:")
    god = GodObject()
    god.create_user("Alice"); god.send_email("a@b.com", "Hi"); god.process_payment(99)
    print("\nGOOD:")
    UserService().create("Alice"); EmailService().send("a@b.com", "Hi")
    PaymentService().process(99)

    print("\n=== Anti-Pattern: Tight Coupling ===")
    print("BAD:")
    BadOrderService().place_order()
    print("GOOD:")
